patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..94aab61de4d1 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1137,6 +1137,12 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
     True = simplifyBinOp(Opcode, B, E, FMF, Q);
     False = simplifyBinOp(Opcode, C, F, FMF, Q);

+    // Handle swapped select arms for mul:
+    // (A ? B : C) * (A ? C : B) -> B * C
+    if (!True && !False && Opcode == Instruction::Mul && B == F && C == E)
+      return Builder.CreateMul(B, C, I.getName(), I.hasNoUnsignedWrap(),
+                               I.hasNoSignedWrap());
+
     if (LHS->hasOneUse() && RHS->hasOneUse()) {
       if (False && !True)
         True = Builder.CreateBinOp(Opcode, B, E);

